import { Text, View } from 'react-native';

import { createKangurDuelsHref } from '../duels/duelsHref';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import {
  KangurMobileCard as Card,
  KangurMobileLinkButton as LinkButton,
  KangurMobileScrollScreen,
  KangurMobileSectionTitle,
} from '../shared/KangurMobileUi';
import {
  PLAN_ROUTE,
} from './leaderboard-primitives';
import { useKangurMobileLeaderboard } from './useKangurLeaderboard';
import { useKangurMobileLeaderboardDuels } from './useKangurMobileLeaderboardDuels';
import { LeaderboardStatsSection } from './components/LeaderboardStatsSection';
import { LeaderboardStatus } from './components/LeaderboardStatus';

export function KangurLeaderboardScreen(): React.JSX.Element {
  const { copy } = useKangurMobileI18n();
  const {
    error,
    isLoading,
    isRestoringAuth,
    items,
    visibleCount,
  } = useKangurMobileLeaderboard();
  const duelLeaderboard = useKangurMobileLeaderboardDuels();

  return (
    <KangurMobileScrollScreen
      contentContainerStyle={{
        gap: 18,
        paddingHorizontal: 20,
        paddingVertical: 24,
      }}
    >
        <View style={{ alignItems: 'flex-start', gap: 14 }}>
          <LinkButton
            href='/'
            label={copy({ de: 'Zurück', en: 'Back', pl: 'Wróć' })}
          />

          <KangurMobileSectionTitle
            title={copy({ de: 'Rangliste', en: 'Leaderboard', pl: 'Ranking' })}
            subtitle={copy({
              de: 'Prüfe die letzten Ergebnisse, vergleiche das Duelltempo und springe direkt zurück in die nächsten Lernschritte.',
              en: 'Check the latest results, compare duel momentum, and jump straight back into your next study steps.',
              pl: 'Sprawdź ostatnie wyniki, porównaj tempo w pojedynkach i od razu wróć do kolejnych kroków nauki.',
            })}
          />

          <LeaderboardStatsSection
            copy={copy}
            duelEntriesCount={duelLeaderboard.entries.length}
            duelLoading={duelLeaderboard.isLoading}
            masteryTrackedCount={0}
            visibleCount={visibleCount}
          />

          <View style={{ alignSelf: 'stretch', gap: 10 }}>
            <LinkButton href={PLAN_ROUTE} label={copy({ de: 'Tagesplan jetzt', en: 'Daily plan now', pl: 'Plan dnia teraz' })} stretch />
            <LinkButton href={createKangurDuelsHref()} label={copy({ de: 'Duell-Lobby öffnen', en: 'Open duel lobby', pl: 'Otwórz lobby pojedynków' })} stretch tone='primary' />
          </View>
        </View>

        <LeaderboardStatus 
            error={error} 
            isLoading={isLoading} 
            isRestoringAuth={isRestoringAuth} 
            items={items} 
            copy={copy} 
        />
    </KangurMobileScrollScreen>
  );
}

import { Text, View } from 'react-native';
import { KangurMobileCard as Card, KangurMobileSummaryChip } from '../../shared/KangurMobileUi';
import { type KangurMobileCopy } from '../../i18n/kangurMobileI18n';

interface LeaderboardStatsSectionProps {
    copy: KangurMobileCopy;
    visibleCount: number;
    duelLoading: boolean;
    duelEntriesCount: number;
    masteryTrackedCount: number;
}

export function LeaderboardStatsSection({
    copy,
    visibleCount,
    duelLoading,
    duelEntriesCount,
    masteryTrackedCount,
}: LeaderboardStatsSectionProps): React.JSX.Element {
    return (
        <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
            <KangurMobileSummaryChip
                label={copy({
                    de: `Ergebnisse ${visibleCount}`,
                    en: `Results ${visibleCount}`,
                    pl: `Wyniki ${visibleCount}`,
                })}
            />
            <KangurMobileSummaryChip
                label={
                    duelLoading
                        ? copy({
                            de: 'Duelle werden geladen',
                            en: 'Duels loading',
                            pl: 'Pojedynki wczytywane',
                        })
                        : copy({
                            de: `Duelle ${duelEntriesCount}`,
                            en: `Duels ${duelEntriesCount}`,
                            pl: `Pojedynki ${duelEntriesCount}`,
                        })
                }
                backgroundColor='#eff6ff'
                borderColor='#bfdbfe'
                textColor='#1d4ed8'
            />
            <KangurMobileSummaryChip
                label={copy({
                    de: `Lektionen ${masteryTrackedCount}`,
                    en: `Lessons ${masteryTrackedCount}`,
                    pl: `Lekcje ${masteryTrackedCount}`,
                })}
                backgroundColor='#ecfdf5'
                borderColor='#a7f3d0'
                textColor='#047857'
            />
        </View>
    );
}

import { Text, View } from 'react-native';
import { KangurMobileCard as Card } from '../../shared/KangurMobileUi';
import { type KangurMobileCopy } from '../../i18n/kangurMobileI18n';

function LeaderboardEntryRow({ item }: { item: any }): React.JSX.Element {
  return (
    <View style={{ borderRadius: 22, backgroundColor: item.isCurrentUser ? '#eef2ff' : '#ffffff', borderWidth: 1, borderColor: item.isCurrentUser ? '#c7d2fe' : '#e2e8f0', padding: 16, gap: 8 }}>
      <View style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }}>
        <View style={{ flexDirection: 'row', alignItems: 'center', gap: 10 }}>
          <Text style={{ fontSize: 20, fontWeight: '800', color: '#0f172a' }}>{item.rankLabel}</Text>
          <View>
            <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>{item.playerName}</Text>
            <Text style={{ color: '#64748b', fontSize: 13 }}>{item.metaLabel}</Text>
          </View>
        </View>
        {item.isCurrentUser ? (
          <View style={{ borderRadius: 999, backgroundColor: '#1d4ed8', paddingHorizontal: 10, paddingVertical: 6 }}>
            <Text style={{ color: '#ffffff', fontSize: 12, fontWeight: '700' }}>{item.currentUserBadgeLabel}</Text>
          </View>
        ) : null}
      </View>
      <View style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'flex-end' }}>
        <Text style={{ color: '#475569', fontSize: 14 }}>{item.operationSummary}</Text>
        <View style={{ alignItems: 'flex-end' }}>
          <Text style={{ color: '#1d4ed8', fontSize: 18, fontWeight: '800' }}>{item.scoreLabel}</Text>
          <Text style={{ color: '#64748b', fontSize: 13 }}>{item.timeLabel}</Text>
        </View>
      </View>
    </View>
  );
}

export function LeaderboardStatus({
  error,
  isLoading,
  isRestoringAuth,
  items,
  copy,
}: {
  error: string | null;
  isLoading: boolean;
  isRestoringAuth: boolean;
  items: any[];
  copy: KangurMobileCopy;
}): React.JSX.Element {
  if (isLoading) {
    return (
      <Card padding={20}>
        <Text style={{ color: '#334155', fontSize: 15 }}>
          {isRestoringAuth
            ? copy({ de: 'Die Anmeldung und die Rangliste werden wiederhergestellt...', en: 'Restoring sign-in and leaderboard...', pl: 'Przywracamy logowanie i ranking...' })
            : copy({ de: 'Die Rangliste wird geladen...', en: 'Loading leaderboard...', pl: 'Ładujemy ranking...' })}
        </Text>
      </Card>
    );
  }
  if (error !== null && error !== '') {
    return (
      <Card gap={8} padding={20}>
        <Text style={{ color: '#991b1b', fontWeight: '800', fontSize: 16 }}>
          {copy({ de: 'Rangliste nicht verfügbar', en: 'Leaderboard unavailable', pl: 'Ranking niedostępny' })}
        </Text>
        <Text style={{ color: '#475569', fontSize: 14, lineHeight: 21 }}>
          {error}
        </Text>
      </Card>
    );
  }
  if (items.length === 0) {
    return (
      <Card padding={20}>
        <Text style={{ color: '#334155', fontSize: 15 }}>
          {copy({ de: 'Kein Ergebnis passt zu den aktuellen Filtern.', en: 'No result matches the current filters.', pl: 'Żaden wynik nie pasuje do obecnych filtrów.' })}
        </Text>
      </Card>
    );
  }
  return <View style={{ gap: 10 }}>{items.map((item) => <LeaderboardEntryRow key={item.id} item={item} />)}</View>;
}

import {
  type KANGUR_LEADERBOARD_OPERATION_OPTIONS,
  type KANGUR_LEADERBOARD_USER_OPTIONS,
  buildKangurLeaderboardItems,
  filterKangurLeaderboardScores,
  getKangurLeaderboardOperationOptions,
  getKangurLeaderboardUserOptions,
  type KangurLeaderboardItem,
  type KangurLeaderboardUserFilter,
} from '@kangur/core';
import { useQuery } from '@tanstack/react-query';
import { useMemo, useState } from 'react';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';

type UseKangurMobileLeaderboardOptions = {
  enabled?: boolean;
  limit?: number;
};

type UseKangurMobileLeaderboardResult = {
  error: string | null;
  isLoadingAuth: boolean;
  isLoading: boolean;
  isRestoringAuth: boolean;
  items: KangurLeaderboardItem[];
  operationFilter: string;
  operationOptions: typeof KANGUR_LEADERBOARD_OPERATION_OPTIONS;
  refresh: () => Promise<void>;
  userFilter: KangurLeaderboardUserFilter;
  userOptions: typeof KANGUR_LEADERBOARD_USER_OPTIONS;
  visibleCount: number;
  setOperationFilter: (value: string) => void;
  setUserFilter: (value: KangurLeaderboardUserFilter) => void;
};

const LEADERBOARD_MEDALS = ['🥇', '🥈', '🥉'] as const;

export const useKangurMobileLeaderboard = (
  options: UseKangurMobileLeaderboardOptions = {},
): UseKangurMobileLeaderboardResult => {
  const { copy, locale } = useKangurMobileI18n();
  const enabled = options.enabled ?? true;
  const limit =
    typeof options.limit === 'number' && options.limit > 0
      ? Math.round(options.limit)
      : 10;
  const { apiClient, apiBaseUrl } = useKangurMobileRuntime();
  const { isLoadingAuth, session } = useKangurMobileAuth();
  const [operationFilter, setOperationFilter] = useState('all');
  const [userFilter, setUserFilter] =
    useState<KangurLeaderboardUserFilter>('all');
  const isRestoringAuth =
    isLoadingAuth && session.status !== 'authenticated';

  const scoresQuery = useQuery({
    enabled,
    queryKey: ['kangur-mobile', 'leaderboard', apiBaseUrl],
    queryFn: async () =>
      apiClient.listScores(
        {
          sort: '-score',
          limit: 100,
        },
        {
          cache: 'no-store',
        },
      ),
    staleTime: 30_000,
  });

  const visibleScores = useMemo(
    () =>
      filterKangurLeaderboardScores(scoresQuery.data ?? [], {
        limit,
        operationFilter,
        userFilter,
      }),
    [limit, operationFilter, scoresQuery.data, userFilter],
  );

  const operationOptions = useMemo(
    () => getKangurLeaderboardOperationOptions(locale),
    [locale],
  );

  const userOptions = useMemo(
    () => getKangurLeaderboardUserOptions(locale),
    [locale],
  );

  const items = useMemo(
    () =>
      buildKangurLeaderboardItems({
        currentLearnerId: session.user?.activeLearner?.id,
        currentUserEmail: session.user?.email,
        locale,
        scores: visibleScores,
      }).map((item, index) => ({
        ...item,
        isMedal: index < LEADERBOARD_MEDALS.length,
        rankLabel: LEADERBOARD_MEDALS[index] ?? `${index + 1}.`,
      })),
    [locale, session.user?.activeLearner?.id, session.user?.email, visibleScores],
  );

  return {
    error:
      scoresQuery.error instanceof Error
        ? copy({
            de: 'Die Ergebnisse konnten nicht geladen werden.',
            en: 'Could not load the results.',
            pl: 'Nie udało się pobrać wyników.',
          })
        : null,
    isLoadingAuth,
    isLoading: isRestoringAuth || scoresQuery.isLoading,
    isRestoringAuth,
    items,
    operationFilter,
    operationOptions,
    refresh: async () => {
      await scoresQuery.refetch();
    },
    setOperationFilter,
    setUserFilter,
    userFilter,
    userOptions,
    visibleCount: visibleScores.length,
  };
};

import type { KangurDuelLeaderboardEntry } from '@kangur/contracts/kangur-duels';
import { useQueryClient } from '@tanstack/react-query';
import { useMemo, useState } from 'react';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { useKangurMobileHomeDuelsLeaderboard } from '../home/useKangurMobileHomeDuelsLeaderboard';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import {
  MOBILE_DUEL_DEFAULT_DIFFICULTY,
  MOBILE_DUEL_DEFAULT_OPERATION,
  MOBILE_DUEL_DEFAULT_QUESTION_COUNT,
  MOBILE_DUEL_DEFAULT_TIME_PER_QUESTION_SEC,
} from '../duels/mobileDuelDefaults';

type UseKangurMobileLeaderboardDuelsResult = {
  actionError: string | null;
  challengeLearner: (opponentLearnerId: string) => Promise<string | null>;
  currentEntry: KangurDuelLeaderboardEntry | null;
  currentRank: number | null;
  entries: KangurDuelLeaderboardEntry[];
  error: string | null;
  isActionPending: boolean;
  isAuthenticated: boolean;
  isLoading: boolean;
  pendingLearnerId: string | null;
  refresh: () => Promise<void>;
};

const toLeaderboardDuelsActionErrorMessage = (
  error: unknown,
  copy: ReturnType<typeof useKangurMobileI18n>['copy'],
): string => {
  if (typeof error === 'object' && error && 'status' in error) {
    const status = (error as { status?: number }).status;

    if (status === 401) {
      return copy({
        de: 'Melde dich an, um ein privates Duell zu senden.',
        en: 'Sign in to send a private duel.',
        pl: 'Zaloguj się, aby wysłać prywatny pojedynek.',
      });
    }
  }

  if (!(error instanceof Error)) {
    return copy({
      de: 'Das private Duell konnte nicht erstellt werden.',
      en: 'Could not create the private duel.',
      pl: 'Nie udało się utworzyć prywatnego pojedynku.',
    });
  }

  const message = error.message.trim();
  if (!message) {
    return copy({
      de: 'Das private Duell konnte nicht erstellt werden.',
      en: 'Could not create the private duel.',
      pl: 'Nie udało się utworzyć prywatnego pojedynku.',
    });
  }

  const normalized = message.toLowerCase();
  if (normalized === 'failed to fetch' || normalized.includes('networkerror')) {
    return copy({
      de: 'Das private Duell konnte nicht erstellt werden.',
      en: 'Could not create the private duel.',
      pl: 'Nie udało się utworzyć prywatnego pojedynku.',
    });
  }

  return message;
};

export const useKangurMobileLeaderboardDuels =
  (): UseKangurMobileLeaderboardDuelsResult => {
    const queryClient = useQueryClient();
    const { copy } = useKangurMobileI18n();
    const { apiBaseUrl, apiClient } = useKangurMobileRuntime();
    const duelLeaderboard = useKangurMobileHomeDuelsLeaderboard();
    const { session } = useKangurMobileAuth();
    const [actionError, setActionError] = useState<string | null>(null);
    const [isActionPending, setIsActionPending] = useState(false);
    const [pendingLearnerId, setPendingLearnerId] = useState<string | null>(null);
    const activeLearnerId = session.user?.activeLearner?.id ?? session.user?.id ?? null;
    const isAuthenticated = session.status === 'authenticated';
    const leaderboardQueryKey = [
      'kangur-mobile',
      'home',
      'duels-leaderboard',
      apiBaseUrl,
    ] as const;

    const currentRank = useMemo(() => {
      if (!activeLearnerId) {
        return -1;
      }

      return duelLeaderboard.entries.findIndex((entry) => entry.learnerId === activeLearnerId);
    }, [activeLearnerId, duelLeaderboard.entries]);

    return {
      actionError,
      challengeLearner: async (opponentLearnerId) => {
        setActionError(null);
        setIsActionPending(true);
        setPendingLearnerId(opponentLearnerId);

        try {
          const response = await apiClient.createDuel(
            {
              difficulty: MOBILE_DUEL_DEFAULT_DIFFICULTY,
              mode: 'challenge',
              operation: MOBILE_DUEL_DEFAULT_OPERATION,
              opponentLearnerId,
              questionCount: MOBILE_DUEL_DEFAULT_QUESTION_COUNT,
              timePerQuestionSec: MOBILE_DUEL_DEFAULT_TIME_PER_QUESTION_SEC,
              visibility: 'private',
            },
            { cache: 'no-store' },
          );

          await queryClient.invalidateQueries({ queryKey: leaderboardQueryKey });
          return response.session.id;
        } catch (error) {
          setActionError(toLeaderboardDuelsActionErrorMessage(error, copy));
          return null;
        } finally {
          setIsActionPending(false);
          setPendingLearnerId(null);
        }
      },
      currentEntry: currentRank >= 0 ? duelLeaderboard.entries[currentRank] ?? null : null,
      currentRank: currentRank >= 0 ? currentRank + 1 : null,
      entries: duelLeaderboard.entries,
      error: duelLeaderboard.error,
      isActionPending,
      isAuthenticated,
      isLoading: duelLeaderboard.isLoading,
      pendingLearnerId,
      refresh: duelLeaderboard.refresh,
    };
  };
